let parsed = {};
try { parsed = JSON.parse($json.response); } catch (e) { parsed = {}; }
const valid = ['urgent', 'reply-needed', 'ignore'];
let category = String(parsed.category || '').toLowerCase().trim();
if (!valid.includes(category)) category = 'reply-needed';
const clean = s => String(s == null ? '' : s).replace(/[*_`\[\]]/g, '').replace(/\s+/g, ' ').trim();
const email = $('Email Trigger (IMAP)').item.json;
return { json: {
  ts: new Date().toISOString(),
  from: clean(email.from).slice(0, 200),
  subject: clean(email.subject).slice(0, 300),
  category,
  summary: clean(parsed.summary).slice(0, 300),
  suggested_reply: parsed.suggested_reply && String(parsed.suggested_reply).toLowerCase() !== 'null' ? clean(parsed.suggested_reply).slice(0, 600) : null
}};
